908	
909	 wire   [55:0] soc2nvdla_time_bin_right_shift;
910	
911	 always @(posedge clk or negedge reset_) begin
912	   if (!reset_) begin
913	     {soc2nvdla_time1_bin,soc2nvdla_time0_bin} <= {56{1'b0}};
914	   end else begin
915	     {soc2nvdla_time1_bin,soc2nvdla_time0_bin} <= {soc2nvdla_time1_bin,soc2nvdla_time0_bin} + 1;
916	   end
917	 end
918	
919	 assign  soc2nvdla_time_bin_right_shift = ( {soc2nvdla_time1_bin,soc2nvdla_time0_bin} >> 1) ;
920	
921	 assign  soc2nvdla_time_tick = soc2nvdla_time_bin_right_shift[4];
