937	module bandwidth_mon(
938	    clk,
939	    event0,
940	    event1,
941	    event2,
942	    event3,
943	    holdoff
944	);
945	input clk;
946	input event0;
947	input event1;
948	input event2;
949	input event3;
950	
951	output holdoff;
952	`ifdef EMU_TB
953	assign holdoff = 1'b0;
954	`else
955	  real max_pct;
956	  real current_util;
957	  real window_r;
958	
959	  reg [3999:0] history = 0;
960	  integer counter = 0;
961	  integer window = 100;
962	  integer num_ones;
963	  reg holdoff = 0;
964	  reg disable_throttle = 0;
965	
966	  initial begin
967	    `ifdef VIVADO
968	      max_pct = $value$plusargs("mem_bandwidth_pct=%d");
969	      if(!max_pct) begin
970	    `else
971	      if(!($value$plusargs("mem_bandwidth_pct=%d", max_pct))) begin
972	    `endif
973	        max_pct = 50;
974	    end
975	    `ifdef VIVADO
976	      window = $value$plusargs("mem_bandwidth_window=%d");
977	      if(!window) begin
978	    `else
979	      if(!($value$plusargs("mem_bandwidth_window=%d", window))) begin
980	    `endif
981	        window = 100;
982	    end
983	    `ifndef VERDI_VIEWING
984	//   if(window > 1000) begin `uvm_fatal("PLUSARG_ERR", "mem_bandwidth_window must be less than 1000"); end
985	    if(window > 1000) begin
986			$display( "(%0d) NVDLA_IP_ERROR : mem_bandwidth_window must be less than 1000)", $stime, );
987			$finish;
988		end
989	    `endif
990	
991	
992	    window = 4 * window; //4 events per clock
993	    window_r = window;
994	  end
995	
996	  always @(negedge clk) begin
997	    history[counter  ] = event0;
998	    history[counter+1] = event1;
999	    history[counter+2] = event2;
1000	    history[counter+3] = event3;
1001	
1002	    if(window <= 100) begin
1003	        num_ones = $countones(history[399:0]);
1004	    end else begin
1005	        num_ones = $countones(history);
1006	    end
1007	
1008	    current_util = ((num_ones*1.0) / (window_r*1.0)) * 100.0;
1009	
1010	    holdoff = current_util > max_pct;
1011	
1012	    counter = counter + 4;
1013	    if(counter > (window-4)) counter = 0;
1014	  end
1015	`endif
